import "./css/Formations.css"
import { useState } from "react"
import { ChevronDown, X } from '@boxicons/react'

const Formations = () => {

    const [activeIndex, setActiveIndex] = useState(null)

    const toggleFAQ = (index) => {
        if(activeIndex === index){
            setActiveIndex(null)
        } else {
            setActiveIndex(index)
        }
    }

    return(
        <div className="formations">

            <div className={`faq ${activeIndex === 0 ? "active" : ""}`}>

                <h3 className="faq-title">blablabla</h3>
                {activeIndex === 0 && (<p className="faq-text">Blablabla 2</p>)}
                <button className="faq-toggle" onClick={() => toggleFAQ(0)}>
                    {activeIndex === 0 ? <X /> : <ChevronDown />}
                </button>
            </div>


            <div className={`faq ${activeIndex === 1 ? "active" : ""}`}>

                <h3 className="faq-title">blablabla</h3>
                {activeIndex === 1 && (<p className="faq-text">Blablabla 2</p>)}
                <button 
                    className="faq-toggle"
                    onClick={() => toggleFAQ(1)}>
                    {activeIndex === 1 ? <X /> : <ChevronDown />}
                </button>
            </div>

        </div>
    )
}

export default Formations
